      { "from": "Customer Service", "to": "Notification Service", "contract": "Synchronous HTTP call", "coupling_type": "temporal + behavioral (ANTI-PATTERN)" },
      { "from": "Reporting Service", "to": "Notification Service", "contract": "Synchronous HTTP call", "coupling_type": "temporal + behavioral (ANTI-PATTERN)" },
      { "from": "Order Service", "to": "PostgreSQL (shared)", "contract": "Direct table access with schema prefix", "coupling_type": "database coupling (ANTI-PATTERN)" },
      { "from": "Courier Service", "to": "PostgreSQL (shared)", "contract": "Direct table access with schema prefix", "coupling_type": "database coupling (ANTI-PATTERN)" },
