    { "area": "Reporting data pipeline", "evolution_path": "Once on a dedicated read model fed by events or CDC, can migrate to a data warehouse, add real-time dashboards, or switch to columnar storage" },
    { "area": "Background job infrastructure", "evolution_path": "Proper job queue allows adding job priorities, scheduling, rate limiting, and horizontal scaling of workers without changing job logic" }
