    { "area": "Message broker selection", "reason": "Choice of message broker (RabbitMQ, Kafka, SQS, etc.) creates long-term infrastructure commitment — choose based on actual throughput and ordering requirements" },
    { "area": "Event schema contracts", "reason": "Once domain events are published, their schema becomes a public contract — breaking changes require versioning strategy upfront" }
