    {
      "risk": "Notification Service is a single point of failure for 5 services — if it goes down or slows, all 5 services degrade or fail synchronously",
      "severity": "critical",
      "mitigation": "P1 — Move to async event-driven notification; add circuit breakers as an immediate stopgap"
    },
    {
      "risk": "Reporting Service reading Order tables directly means any Order schema change can silently break reports, with no compile-time or contract-time detection",
      "severity": "high",
      "mitigation": "P1 — Introduce CDC or event-based read model for Reporting; as immediate stopgap, create database views as a stable contract layer"
